  // \u7528\u6CD5\uFF1Aif (siderRuntime.meta.capabilities.includes('cookies')) { ... }
  const RUNTIME_CAPABILITIES = Object.freeze([
    'addElement',
    'addStyle',
    'openInTab',
    'fetch',
    'artifacts',
    'audio',
    'cookies',
    'ai',
    'executeInMainWorld',
    'native',
    'readConsoleMessages',
    'readNetworkRequests',
    'waitFor',
    'waitForSelector',
    'skills',
  ]);

